import React, { useState } from 'react';

const allProjects = [
  [
    { href: 'https://dimacalingtechnicaldocumentation.vercel.app/', img: '/images/technicaldocument.png', title: 'Technical Document Web Page', desc: 'A website in the form of a technical document.', sym: '✕', color: '#7fc5e8' },
    { href: 'https://dimacalingsurvey.vercel.app/', img: '/images/survey.png', title: 'Customer Satisfaction Survey', desc: 'A form that intakes customer feedback.', sym: '○', color: '#e87b7b' },
    { href: 'https://dimacalingtributepage.vercel.app/', img: '/images/tribute.png', title: 'Tribute Page', desc: 'A page that shows gratitude to my brother.', sym: '□', color: '#e87bce' },
  ],
  [
    { href: 'https://dimacalingportfolio.vercel.app/', img: '/images/portfolio.png', title: 'Personal Portfolio', desc: 'A page showcasing my past works.', sym: '△', color: '#7be8b4' },
    { href: 'https://onlineportfoliocc1.vercel.app/', img: '/images/groupwebsite.png', title: 'Group Portfolio', desc: 'Simple web page we made in first-year of university.', sym: '✕', color: '#7fc5e8' },
  ],
];

const Projects = () => {
  const [current, setCurrent] = useState(0);
  const [hoveredCard, setHoveredCard] = useState(null);

  const prev = () => setCurrent((c) => (c === 0 ? allProjects.length - 1 : c - 1));
  const next = () => setCurrent((c) => (c === allProjects.length - 1 ? 0 : c + 1));

  return (
    <section
      id="Projects"
      className="flex flex-col items-center px-10 pt-24 pb-16"
      style={{ background: 'var(--ps-navy, #0a0f2e)' }}
    >
      <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">My Projects</h1>

      <div className="relative w-full max-w-4xl">
        <div className="flex justify-center gap-6 flex-wrap">
          {allProjects[current].map((project, i) => {
            const isHov = hoveredCard === i;
            return (
              <a
                key={i}
                href={project.href}
                target="_blank"
                rel="noreferrer"
                className="no-underline"
                style={{ textDecoration: 'none' }}
              >
                <div
                  className="rounded-xl overflow-hidden text-center transition-all duration-300 hover:-translate-y-2"
                  style={{
                    width: '220px',
                    background: 'rgba(0,55,145,0.2)',
                    border: isHov ? `1px solid ${project.color}88` : '1px solid rgba(0,112,204,0.2)',
                    boxShadow: isHov ? `0 0 20px ${project.color}44` : 'none',
                    transition: 'border 0.3s, box-shadow 0.3s',
                  }}
                  onMouseEnter={() => setHoveredCard(i)}
                  onMouseLeave={() => setHoveredCard(null)}
                >
                  <img
                    src={project.img}
                    alt={project.title}
                    className="w-full object-cover"
                    style={{ height: '150px' }}
                  />
                  <div className="p-4">
                    <div className="flex items-center justify-center gap-1 mb-1">
                      <span style={{ color: project.color, fontSize: '11px' }}>{project.sym}</span>
                      <h5 className="font-bold text-xs" style={{ color: project.color }}>{project.title}</h5>
                    </div>
                    <p className="text-xs" style={{ color: 'rgba(255,255,255,0.55)' }}>{project.desc}</p>
                  </div>
                </div>
              </a>
            );
          })}
        </div>

        {/* Nav arrows */}
        {[{ dir: 'prev', label: '‹', side: '-left-6', action: prev }, { dir: 'next', label: '›', side: '-right-6', action: next }].map(({ label, side, action }) => (
          <button
            key={label}
            onClick={action}
            className={`absolute ${side} top-1/2 -translate-y-1/2 w-10 h-10 rounded-full text-white text-xl font-bold flex items-center justify-center transition hover:opacity-80`}
            style={{ background: 'rgba(0,55,145,0.6)', border: '1px solid rgba(0,112,204,0.4)', cursor: 'pointer' }}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Dot indicators */}
      <div className="flex gap-3 mt-8">
        {allProjects.map((_, i) => (
          <button
            key={i}
            onClick={() => setCurrent(i)}
            className="border-0 cursor-pointer transition-all rounded-full"
            style={{
              width: i === current ? '24px' : '10px',
              height: '10px',
              background: i === current ? '#7fc5e8' : 'rgba(255,255,255,0.2)',
              transition: 'width 0.3s, background 0.3s',
            }}
          />
        ))}
      </div>
    </section>
  );
};

export default Projects;
